 46	/****************************************************************************
 47	 * Name: board_button_initialize
 48	 *
 49	 * Description:
 50	 *   board_button_initialize() must be called to initialize button resources.
 51	 *   After that, board_buttons() may be called to collect the current state
 52	 *   of all buttons or board_button_irq() may be called to register button
 53	 *   interrupt handlers.
 54	 *
 55	 ****************************************************************************/
 56	
 57	uint32_t board_button_initialize(void)
 58	{
 59	  esp32s3_configgpio(BUTTON_BOOT, INPUT_FUNCTION_2 | PULLUP);
 60	  return 1;
 61	}
 62	
 63	/****************************************************************************
 64	 * Name: board_buttons
 65	 *
 66	 * Description:
 67	 *   After board_button_initialize() has been called, board_buttons() may be
 68	 *   called to collect the state of all buttons.  board_buttons() returns an
 69	 *   8-bit bit set with each bit associated with a button.  See the
 70	 *   BUTTON_*_BIT  definitions in board.h for the meaning of each bit.
 71	 *
 72	 ****************************************************************************/
 73	
 74	uint32_t board_buttons(void)
 75	{
 76	  uint8_t ret = 0;
 77	  int i = 0;
 78	  int n = 0;
 79	
 80	  bool b0 = esp32s3_gpioread(BUTTON_BOOT);
 81	
 82	  for (i = 0; i < 10; i++)
 83	    {
 84	      up_mdelay(1);
 85	
 86	      bool b1 = esp32s3_gpioread(BUTTON_BOOT);
 87	
 88	      if (b0 == b1)
 89	        {
 90	          n++;
 91	        }
 92	      else
 93	        {
 94	          n = 0;
 95	        }
 96	
 97	      if (3 == n)
 98	        {
 99	          break;
100	        }
101	
102	      b0 = b1;
103	    }
104	
105	  iinfo("b=%d n=%d\n", b0, n);
106	
107	  /* Low value means that the button is pressed */
108	
109	  if (!b0)
110	    {
111	      ret = 0x1;
112	    }
113	
114	  return ret;
115	}
