117	/****************************************************************************
118	 * Name: board_button_irq
119	 *
120	 * Description:
121	 *   board_button_irq() may be called to register an interrupt handler that
122	 *   will be called when a button is depressed or released.  The ID value is
123	 *   a button enumeration value that uniquely identifies a button resource.
124	 *   See the BUTTON_* definitions in board.h for the meaning of enumeration
125	 *   value.
126	 *
127	 ****************************************************************************/
128	
129	#ifdef CONFIG_ARCH_IRQBUTTONS
130	int board_button_irq(int id, xcpt_t irqhandler, void *arg)
131	{
132	  int ret;
133	  DEBUGASSERT(id == 0);
134	
135	  int irq = ESP32S3_PIN2IRQ(BUTTON_BOOT);
136	
137	  if (irqhandler != NULL)
138	    {
139	      /* Make sure the interrupt is disabled */
140	
141	      esp32s3_gpioirqdisable(irq);
142	
143	      ret = irq_attach(irq, irqhandler, arg);
144	      if (ret < 0)
145	        {
146	          syslog(LOG_ERR, "ERROR: irq_attach() failed: %d\n", ret);
147	          return ret;
148	        }
149	
150	      gpioinfo("Attach %p\n", irqhandler);
151	
152	      gpioinfo("Enabling the interrupt\n");
153	
154	      /* Configure the interrupt for rising and falling edges */
155	
156	      esp32s3_gpioirqenable(irq, CHANGE);
157	    }
158	  else
159	    {
160	      gpioinfo("Disable the interrupt\n");
161	      esp32s3_gpioirqdisable(irq);
162	    }
163	
164	  return OK;
165	}
166	#endif

